insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('d4531c92-643e-56d1-9668-b73e67aa3f2b', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "I grew up in a quiet neighborhood near the park.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/d4531c92-643e-56d1-9668-b73e67aa3f2b.mp3"}'::jsonb, '{"value": "neighborhood", "accepted": ["neighborhood"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('b997177d-e295-5c11-8830-109567a503b1', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "They live on a wide, tree-lined avenue.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b997177d-e295-5c11-8830-109567a503b1.mp3"}'::jsonb, '{"value": "avenue", "accepted": ["avenue"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('128e2b2d-dda5-54fd-9bad-c1c2776c2f9d', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "We walked across the old stone bridge.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/128e2b2d-dda5-54fd-9bad-c1c2776c2f9d.mp3"}'::jsonb, '{"value": "bridge", "accepted": ["bridge"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('aef06e9d-5205-5c2a-8228-2c7116a5f802', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "Children were playing on the sidewalk outside.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/aef06e9d-5205-5c2a-8228-2c7116a5f802.mp3"}'::jsonb, '{"value": "sidewalk", "accepted": ["sidewalk"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('be46085f-9fd2-5fbc-892f-f65779eb9bc2', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "My office is located downtown by the river.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/be46085f-9fd2-5fbc-892f-f65779eb9bc2.mp3"}'::jsonb, '{"value": "downtown", "accepted": ["downtown"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('111dc29c-184e-52c4-9e41-4c2979816d1f', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "Tourists gathered in the main square all afternoon.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/111dc29c-184e-52c4-9e41-4c2979816d1f.mp3"}'::jsonb, '{"value": "square", "accepted": ["square"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('5d6fa588-b279-539d-bf01-e4ea92546dd9', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "That tall building has forty floors.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/5d6fa588-b279-539d-bf01-e4ea92546dd9.mp3"}'::jsonb, '{"value": "building", "accepted": ["building"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('b36826af-48a6-566a-8f45-169c25f53c4c', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "The bakery is on the corner of my street.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b36826af-48a6-566a-8f45-169c25f53c4c.mp3"}'::jsonb, '{"value": "corner", "accepted": ["corner"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('82ac93e7-57b6-5eea-a8a2-44b8781eab6e', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "There was heavy traffic on the highway this morning.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/82ac93e7-57b6-5eea-a8a2-44b8781eab6e.mp3"}'::jsonb, '{"value": "traffic", "accepted": ["traffic"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('49d50502-b79c-50e1-8e4c-1c08d5df206f', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "She lives on a narrow street in the city.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/49d50502-b79c-50e1-8e4c-1c08d5df206f.mp3"}'::jsonb, '{"value": "street", "accepted": ["street"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('8ba1157b-6d2e-5386-a0fe-7d9f9df7edb5', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "This road leads to the next town.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/8ba1157b-6d2e-5386-a0fe-7d9f9df7edb5.mp3"}'::jsonb, '{"value": "road", "accepted": ["road"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('6f722284-3a24-5bdb-a3f4-4d869a59c942', '20000000-0000-0000-0000-000000000001', 'A2', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "I borrowed three books from the public library.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/6f722284-3a24-5bdb-a3f4-4d869a59c942.mp3"}'::jsonb, '{"value": "library", "accepted": ["library"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('5d5436c5-4d1e-59dc-ade3-886434636836', '20000000-0000-0000-0000-000000000001', 'A2', 'reading', 'match', 'Empareja cada palabra con su traducción.', '{"pairs": [{"en": "neighborhood", "es": "barrio"}, {"en": "avenue", "es": "avenida"}, {"en": "bridge", "es": "puente"}, {"en": "sidewalk", "es": "acera"}, {"en": "downtown", "es": "centro"}]}'::jsonb, '{"pairs": [["neighborhood", "barrio"], ["avenue", "avenida"], ["bridge", "puente"], ["sidewalk", "acera"], ["downtown", "centro"]]}'::jsonb, 0.15, array['vocab_f1','reading']) on conflict (id) do nothing;
