insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('c0b82ffa-0b34-5330-bfda-e5ec394c3068', '20000000-0000-0000-0000-000000000001', 'B1', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "She got angry when they arrived late again.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/c0b82ffa-0b34-5330-bfda-e5ec394c3068.mp3"}'::jsonb, '{"value": "angry", "accepted": ["angry"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('98058d8b-5334-55a1-8cec-49d6b8874543', '20000000-0000-0000-0000-000000000001', 'B1', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "Try to stay calm during the difficult meeting.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/98058d8b-5334-55a1-8cec-49d6b8874543.mp3"}'::jsonb, '{"value": "calm", "accepted": ["calm"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('6f2063a7-308f-575d-98e5-28c5c9b98294', '20000000-0000-0000-0000-000000000001', 'B1', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "It is rude to interrupt while others talk.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/6f2063a7-308f-575d-98e5-28c5c9b98294.mp3"}'::jsonb, '{"value": "rude", "accepted": ["rude"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
insert into content_items(id,course_id,cefr_level,skill,type,prompt,payload,correct_answer,difficulty,tags) values ('4980fae4-36c3-5241-aa99-8eea3045555d', '20000000-0000-0000-0000-000000000001', 'B1', 'writing', 'cloze', 'Completa la frase con la palabra que falta.', '{"text": "The waiter was friendly and very polite.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/4980fae4-36c3-5241-aa99-8eea3045555d.mp3"}'::jsonb, '{"value": "polite", "accepted": ["polite"]}'::jsonb, 0.35, array['vocab_f1','writing']) on conflict (id) do nothing;
